Literal.Value:
'{
  "$schema": "https://vega.github.io/schema/vega-lite/v5.json",
  "data": { "name": "dataset" },

  "config": {
    "view": { "stroke": null },
    "axis": { "grid": true, "tickSize": 3, "labelFontSize": 11, "title": null },
    "scale": { "bandPaddingInner": 0.25, "bandPaddingOuter": 0.15 },
    "legend": { "labelFontSize": 11, "titleFontSize": 11 }
  },

  "resolve": {
    "scale": {
      "color": "independent",
      "stroke": "independent"
    }
  },

  "transform": [
    { "filter": "datum.PatientID != null" },
    { "calculate": "toDate(datum.Start)", "as": "StartDate" },
    { "calculate": "toDate(datum.End)", "as": "EndDate" },

    {
      "calculate": "split(datum.Lane,''|'')[1] == ''Track'' ? split(datum.Lane,''|'')[2] : null",
      "as": "Discipline"
    },
    {
      "calculate": "datum.Discipline == ''PT'' ? ''01'' : datum.Discipline == ''OT'' ? ''02'' : datum.Discipline == ''ST'' ? ''03'' : ''99''",
      "as": "DisciplineOrder"
    },
    {
      "calculate": "split(datum.Lane,''|'')[1] == ''Track'' ? ''06|Track|'' + datum.DisciplineOrder + ''|'' + datum.Discipline : datum.Lane",
      "as": "LaneSortKey"
    },

    {
      "calculate": "datum.EventType == ''Payer'' ? (indexof(datum.Detail, '') '') >= 0 ? substring(datum.Detail, indexof(datum.Detail, '') '') + 2) : datum.Detail) : datum.Detail",
      "as": "DetailClean"
    },

    {
      "calculate": "split(datum.LaneSortKey,''|'')[1] == ''Track'' ? split(datum.LaneSortKey,''|'')[3] : join(slice(split(datum.LaneSortKey,''|''),1),''|'')",
      "as": "LaneLabel"
    },
    {
      "calculate": "datum.StartDate != null && datum.EndDate != null ? floor((datum.EndDate - datum.StartDate) / 86400000) : null",
      "as": "DurationDays"
    },

    { "filter": "datum.EventType != ''Residence'' || datum.Detail != null" },
    { "filter": "datum.EventType != ''Payer'' || datum.DetailClean != null" }
  ],

  "encoding": {
    "y": {
      "field": "LaneSortKey",
      "type": "nominal",
      "sort": { "op": "min", "field": "LaneSortKey" },
      "axis": {
        "grid": true,
        "labelLimit": 340,
        "labelExpr": "split(datum.label,''|'')[1] == ''Track'' ? '' '' + split(datum.label,''|'')[3] : join(slice(split(datum.label,''|''),1),''|'')"
      }
    }
  },

  "layer": [
    {
      "name": "spans_main",
      "transform": [
        {
          "filter": "datum.StartDate != null && datum.EndDate != null && datum.EndDate != datum.StartDate && datum.EventType != ''Visit'' && datum.EventType != ''Screen'' && datum.EventType != ''Residence'' && datum.EventType != ''Payer''"
        }
      ],
      "mark": { "type": "bar", "cornerRadius": 2, "strokeWidth": 1.4 },
      "encoding": {
        "x": {
          "field": "StartDate",
          "type": "temporal",
          "axis": {
            "title": null,
            "tickCount": { "interval": "month", "step": 1 },
            "labelExpr": "timeFormat(datum.value, ''%b'') + (month(datum.value) == 0 ? '' '' + timeFormat(datum.value, ''%Y'') : '''')",
            "labelAngle": 0,
            "labelPadding": 6
          }
        },
        "x2": { "field": "EndDate" },
        "y": { "field": "LaneSortKey", "type": "nominal" },

        "color": { "value": "#0c436a" },
        "stroke": { "value": "#0c436a" },

        "opacity": {
          "condition": {
            "test": "datum.LaneGroup == ''06|Track''",
            "value": 0.28
          },
          "value": 0.85
        },

        "size": { "value": 20 },

        "tooltip": [
          { "field": "EventType", "type": "nominal", "title": "Event" },
          { "field": "LaneLabel", "type": "nominal", "title": "Lane" },
          { "field": "Detail", "type": "nominal", "title": "Detail" },
          { "field": "StartDate", "type": "temporal", "title": "Start" },
          { "field": "EndDate", "type": "temporal", "title": "End" },
          { "field": "DurationDays", "type": "quantitative", "title": "Days" },
          { "field": "ItemID", "type": "nominal", "title": "ItemID" }
        ]
      }
    },

    {
      "name": "residence_spans",
      "transform": [
        {
          "filter": "datum.StartDate != null && datum.EndDate != null && datum.EndDate != datum.StartDate && datum.EventType == ''Residence''"
        }
      ],
      "mark": { "type": "bar", "cornerRadius": 2, "strokeWidth": 1.4 },
      "encoding": {
        "x": {
          "field": "StartDate",
          "type": "temporal",
          "axis": {
            "title": null,
            "tickCount": { "interval": "month", "step": 1 },
            "labelExpr": "timeFormat(datum.value, ''%b'') + (month(datum.value) == 0 ? '' '' + timeFormat(datum.value, ''%Y'') : '''')",
            "labelAngle": 0,
            "labelPadding": 6
          }
        },
        "x2": { "field": "EndDate" },
        "y": { "field": "LaneSortKey", "type": "nominal" },

        "color": {
          "field": "Detail",
          "type": "nominal",
          "scale": { "scheme": "greens" },
          "legend": { "title": "Residence" }
        },
        "stroke": {
          "field": "Detail",
          "type": "nominal",
          "scale": { "scheme": "greens" },
          "legend": null
        },

        "opacity": { "value": 0.85 },
        "size": { "value": 20 },

        "tooltip": [
          { "field": "EventType", "type": "nominal", "title": "Event" },
          { "field": "Detail", "type": "nominal", "title": "Residence" },
          { "field": "StartDate", "type": "temporal", "title": "Start" },
          { "field": "EndDate", "type": "temporal", "title": "End" },
          { "field": "DurationDays", "type": "quantitative", "title": "Days" },
          { "field": "ItemID", "type": "nominal", "title": "ItemID" }
        ]
      }
    },

    {
      "name": "payer_spans",
      "transform": [
        {
          "filter": "datum.StartDate != null && datum.EndDate != null && datum.EndDate != datum.StartDate && datum.EventType == ''Payer''"
        }
      ],
      "mark": { "type": "bar", "cornerRadius": 2, "strokeWidth": 1.4 },
      "encoding": {
        "x": {
          "field": "StartDate",
          "type": "temporal",
          "axis": {
            "title": null,
            "tickCount": { "interval": "month", "step": 1 },
            "labelExpr": "timeFormat(datum.value, ''%b'') + (month(datum.value) == 0 ? '' '' + timeFormat(datum.value, ''%Y'') : '''')",
            "labelAngle": 0,
            "labelPadding": 6
          }
        },
        "x2": { "field": "EndDate" },
        "y": { "field": "LaneSortKey", "type": "nominal" },

        "color": {
          "field": "DetailClean",
          "type": "nominal",
          "scale": { "scheme": "purples" },
          "legend": { "title": "Payer" }
        },
        "stroke": {
          "field": "DetailClean",
          "type": "nominal",
          "scale": { "scheme": "purples" },
          "legend": null
        },

        "opacity": { "value": 0.85 },
        "size": { "value": 20 },

        "tooltip": [
          { "field": "EventType", "type": "nominal", "title": "Event" },
          { "field": "DetailClean", "type": "nominal", "title": "Payer" },
          { "field": "StartDate", "type": "temporal", "title": "From" },
          { "field": "EndDate", "type": "temporal", "title": "Thru" },
          { "field": "DurationDays", "type": "quantitative", "title": "Days" },
          { "field": "ItemID", "type": "nominal", "title": "ItemID" }
        ]
      }
    },

    {
      "name": "visits_ticks",
      "transform": [
        { "filter": "datum.StartDate != null && datum.EventType == ''Visit''" },
        { "calculate": "''Skilled Visit''", "as": "VisitLegend" }
      ],
      "mark": {
        "type": "tick",
        "orient": "vertical",
        "thickness": 1.2, // ← controls chart tick thickness ONLY
        "size": 8
      },
      "encoding": {
        "x": {
          "field": "StartDate",
          "type": "temporal"
        },
        "y": {
          "field": "LaneSortKey",
          "type": "nominal"
        },

        "stroke": {
          "field": "VisitLegend",
          "type": "nominal",
          "scale": {
            "domain": ["Skilled Visit"],
            "range": ["#0c436a"]
          },
          "legend": {
            "symbolType": "stroke",
            "symbolStrokeWidth": 2.5,
            "symbolSize": 120
          }
        },

        "detail": { "field": "ItemID" }
      }
    },
    {
      "name": "screens_points",
      "transform": [
        { "filter": "datum.StartDate != null && datum.EventType == ''Screen''" }
      ],
      "mark": {
        "type": "point",
        "shape": "diamond",
        "filled": true,
        "size": 110
      },
      "encoding": {
        "x": {
          "field": "StartDate",
          "type": "temporal",
          "axis": {
            "title": null,
            "tickCount": { "interval": "month", "step": 1 },
            "labelExpr": "timeFormat(datum.value, ''%b'') + (month(datum.value) == 0 ? '' '' + timeFormat(datum.value, ''%Y'') : '''')",
            "labelAngle": 0,
            "labelPadding": 6
          }
        },
        "y": { "field": "LaneSortKey", "type": "nominal" },

        "fill": { "value": "#5F6B6D" },
        "stroke": { "value": "#0c436a" },
        "strokeWidth": { "value": 1.4 },

        "detail": { "field": "ItemID" },
        "tooltip": [
          { "field": "EventType", "type": "nominal", "title": "Event" },
          { "field": "Detail", "type": "nominal", "title": "Screen" },
          { "field": "StartDate", "type": "temporal", "title": "Date" },
          { "field": "ItemID", "type": "nominal", "title": "ItemID" }
        ]
      }
    }
  ]
}'
